{"procName":"dbo.tr_thongke_nhapxuat_send2","body":"CREATE   PROCEDURE [dbo].[TR_THONGKE_NHAPXUAT_SEND2](@ngaythang date)
AS
BEGIN
    SELECT A.makho, B.mavt, (B.slnhap + B.soluong_du) AS soluong_nhap
    INTO #PHIEUNHAP
    FROM tr_phieunhap A
        INNER JOIN tr_ctphieunhap B ON A.sopn = B.sopn
    WHERE A.active = 1 AND A.ngayphieu = @ngaythang

    SELECT A.makho, B.mact, B.soluong AS soluong_xuat
    INTO #PHIEUXUAT
    FROM tr_phieuxuat A
        INNER JOIN tr_ctphieuxuat B ON A.sopx = B.phieuxuat
    WHERE A.active = 1 AND CAST(A.ngaytao AS DATE) = @ngaythang

    SELECT ISNULL(A.makho, B.makho) as makho,
        ISNULL(A.mavt, B.mact) as mavt,
        SUM(ISNULL(A.soluong_nhap, 0)) as soluong_nhap,
        SUM(ISNUll(B.soluong_xuat, 0)) as soluong_xuat
    INTO #NHAPXUAT
    FROM #PHIEUNHAP A
        FULL JOIN #PHIEUXUAT B ON A.makho = B.makho AND A.mavt = B.mact
    GROUP BY ISNULL(A.makho, B.makho), ISNULL(A.mavt, B.mact)

    SELECT A.makho, D.[description] as tenkho, A.mavt, C.mota, C.quycach, C.mausac, C.dvt, 
        A.soluong_nhap, A.soluong_xuat, B.soluong as soluong_ton
	INTO #NHAPXUAT1
    FROM #NHAPXUAT A
        INNER JOIN tr_tonkho_sum B ON A.mavt = B.mavt
        INNER JOIN tr_material C ON A.mavt = C.mavt
        INNER JOIN tr_site D ON A.makho = D.[name]
    --ORDER BY A.makho, C.mota;
    
	DECLARE @html nvarchar(max) = '';
	IF EXISTS (SELECT * FROM #NHAPXUAT1)
	BEGIN
		SET @html = N'<html>';
		SET @html = @html + char(13) + char(10) + N'<head>';
		SET @html = @html + char(13) + char(10) + N'<meta charset="UTF-8">';
		SET @html = @html + char(13) + char(10) + N'<meta name="viewport" content="initial-scale=1.0">';
		SET @html = @html + char(13) + char(10) + N'</head>';
		SET @html = @html + char(13) + char(10) + N'<body>';
		SET @html = @html + char(13) + char(10) + N'<h1 style=''TEXT-ALIGN: CENTER''>THỐNG KÊ NHẬP XUẤT KHO</h1>';
		SET @html = @html + char(13) + char(10) + N'<p>Ngày ' + FORMAT(@ngaythang, 'dd/MM/yyyy') + '</p>';
		SET @html = @html + char(13) + char(10) + N'<table border=''1'' cellSpacing=''0'' cellPadding=''2'' style=''width: 1250px; BACKGROUND-COLOR: #ffffff; POSITION: relative; EMPTY-CELLS: show;''>';
		SET @html = @html + char(13) + char(10) + N'<tbody>';

		-- HEADER
		SET @html = @html + char(13) + char(10) + N'<tr>';
		SET @html = @html + char(13) + char(10) + N'<th>Mã chi tiết</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Tên chi tiết</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Quy cách</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Màu sắc</th>';
		SET @html = @html + char(13) + char(10) + N'<th>ĐVT</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Số lượng nhập</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Số lượng xuất</th>';
		SET @html = @html + char(13) + char(10) + N'<th>Tồn kho hiện tại</th>';
		SET @html = @html + char(13) + char(10) + N'</tr>';

		DECLARE @tenkho1 nvarchar(200) = '';
		DECLARE CUR CURSOR LOCAL FOR
			SELECT makho, tenkho, mavt, mota, quycach, mausac, dvt,
				soluong_nhap, soluong_xuat, soluong_ton
			FROM #NHAPXUAT1 
			ORDER BY makho, mota
		OPEN CUR
		DECLARE @makho nvarchar(50) = '', @tenkho nvarchar(200) = '', @mavt nvarchar(200) = '', @mota nvarchar(200) = '', @quycach nvarchar(200) = '', @mausac nvarchar(200) = '', @dvt nvarchar(50) = '';
		DECLARE @soluong_nhap float = 0, @soluong_xuat float = 0, @soluong_ton float = 0;
		FETCH NEXT FROM CUR INTO @makho, @tenkho, @mavt, @mota, @quycach, @mausac, @dvt, @soluong_nhap, @soluong_xuat, @soluong_ton
		WHILE @@FETCH_STATUS = 0
		BEGIN
			IF @tenkho1 <> @tenkho
			BEGIN
				SET @html = @html + char(13) + char(10) + N'<tr style=''font-weight: bold''>';
				SET @html = @html + char(13) + char(10) + N'<td colSpan=''8''>Kho: ' + @tenkho + '</td>';
				SET @html = @html + char(13) + char(10) + N'</tr>';

				SET @tenkho1 = @tenkho;
			END

			SET @html = @html + char(13) + char(10) + N'<tr>';
			SET @html = @html + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: center;''>' + ISNULL(@mavt, '') + '</td>';
			SET @html = @html + char(13) + char(10) + N'<td style=''width: 200px; VERTICAL-ALIGN: middle; TEXT-ALIGN: left;''>' + ISNULL(@mota, '') + '</td>';
			SET @html = @html + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: center;''>' + ISNULL(@quycach, '') + '</td>';
			SET @html = @html + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: center;''>' + ISNULL(@mausac, '') + '</td>';
			SET @html = @html + char(13) + char(10) + N'<td style=''width: 50px; VERTICAL-ALIGN: middle; TEXT-ALIGN: center;''>' + ISNULL(@dvt, '') + '</td>';
			SET @html = @html + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + FORMAT(@soluong_nhap, '#,0.###') + '</td>';
			SET @html = @html + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + FORMAT(@soluong_xuat, '#,0.###') + '</td>';
			SET @html = @html + char(13) + char(10) + N'<td style=''width: 100px; VERTICAL-ALIGN: middle; TEXT-ALIGN: right;''>' + FORMAT(@soluong_ton, '#,0.##') + '</td>';
			SET @html = @html + char(13) + char(10) + N'</tr>';

			FETCH NEXT FROM CUR INTO @makho, @tenkho, @mavt, @mota, @quycach, @mausac, @dvt, @soluong_nhap, @soluong_xuat, @soluong_ton
		END
		CLOSE CUR;
		DEALLOCATE CUR;

		SET @html = @html + char(13) + char(10) + N'</tbody>';
		SET @html = @html + char(13) + char(10) + N'</table>';
		SET @html = @html + char(13) + char(10) + N'</body></html>';

	END

	SELECT @html AS body
    DROP TABLE #PHIEUNHAP, #PHIEUXUAT, #NHAPXUAT, #NHAPXUAT1;
END


","parseAnalysis":{"readsTables":["dbo.cur","dbo.tr_ctphieunhap","dbo.tr_ctphieuxuat","dbo.tr_material","dbo.tr_phieunhap","dbo.tr_phieuxuat","dbo.tr_site","dbo.tr_tonkho_sum"],"writesTables":[],"flags":["has-cursor","has-while","has-group-by","has-temp-table"],"suggestedTier":"D"},"tablesEnriched":{"dbo.dqt_pallet_chitiet":"dqt_pallet_chitiet","dbo.dqt_thongke_phoi":"dqt_thongke_phoi","dbo.mes_hoso_donhang":"mes_hoso_donhang","dbo.ps_kehoach_donhang":"ps_kehoach_donhang","dbo.ps_kehoach_donhang_trangthai":"ps_kehoach_donhang_trangthai","dbo.tr_bophan":"tr_bophan","dbo.tr_chitiet_hangtrang":"tr_chitiet_hangtrang","dbo.tr_common":"tr_common","dbo.tr_dinhmuc_donggoi":"tr_dinhmuc_donggoi","dbo.tr_dinhmuc_govan":"tr_dinhmuc_govan","dbo.tr_dinhmuc_hangtrang":"tr_dinhmuc_hangtrang","dbo.tr_dinhmuc_ngukim":"tr_dinhmuc_ngukim","dbo.tr_dinhmuc_son":"tr_dinhmuc_son","dbo.tr_dinhmuc_son_new":"tr_dinhmuc_son_new","dbo.tr_dinhmuc_son_theomau":"tr_dinhmuc_son_theomau","dbo.tr_dondathang":"tr_dondathang","dbo.tr_dondathang_chitiet":"tr_dondathang_chitiet","dbo.tr_gridview_column":"tr_gridview_column","dbo.tr_luutrinh_sanxuat":"tr_luutrinh_sanxuat","dbo.tr_material":"tr_material","dbo.tr_nguyenlieu_gva":"tr_nguyenlieu_gva","dbo.tr_order":"tr_order","dbo.tr_order_detail":"tr_order_detail","dbo.tr_sanpham":"tr_sanpham","dbo.tr_tinhtrang_fsc":"tr_tinhtrang_fsc"}}
